import{_ as o,c as s,o as n,ag as r}from"./chunks/framework.GdcW6lnn.js";const I=JSON.parse('{"title":"","description":"","frontmatter":{},"headers":[],"relativePath":"basics_api/gateways.md","filePath":"basics_api/gateways.md"}'),a={name:"basics_api/gateways.md"};function g(e,t,i,l,A,P){return n(),s("div",null,t[0]||(t[0]=[r('<h3 id="🚪-шлюзи-gateways-централізоване-керування-вашими-api" tabindex="-1">🚪 Шлюзи (Gateways): Централізоване керування вашими API <a class="header-anchor" href="#🚪-шлюзи-gateways-централізоване-керування-вашими-api" aria-label="Permalink to “🚪 Шлюзи (Gateways): Централізоване керування вашими API”">​</a></h3><p>API Gateway (шлюз API) - це <strong>єдина точка входу</strong> для всіх клієнтських запитів до ваших бекенд-сервісів API. Він діє як <strong>посередник</strong> 🛂, обробляючи вхідні запити та перенаправляючи їх до відповідних служб, а також виконуючи ряд інших важливих функцій для керування, безпеки та масштабування ваших API.</p><p>Ось детальніший огляд згаданих шлюзів API:</p><h4 id="☁️-aws-api-gateway-amazon-web-services" tabindex="-1">☁️ AWS API Gateway (Amazon Web Services) <a class="header-anchor" href="#☁️-aws-api-gateway-amazon-web-services" aria-label="Permalink to “☁️ AWS API Gateway (Amazon Web Services)”">​</a></h4><p><strong>Що це?</strong></p><p>AWS API Gateway - це повністю керований сервіс від Amazon Web Services, який дозволяє розробникам створювати, публікувати, підтримувати, контролювати та захищати API в будь-якому масштабі. Він підтримує RESTful API, WebSocket API та HTTP API.</p><p><strong>Основні можливості:</strong></p><ul><li><strong>Створення та керування API:</strong> Просте визначення маршрутів, методів, параметрів запитів та відповідей через консоль AWS, CLI або SDK.</li><li><strong>Авторизація та аутентифікація:</strong> Підтримка різних методів авторизації, включаючи IAM ролі AWS, Lambda Authorizers (кастомні функції авторизації), Cognito User Pools та API Keys.</li><li><strong>Контроль доступу:</strong> Керування тим, хто може отримувати доступ до ваших API.</li><li><strong>Обмеження швидкості (Rate Limiting) та регулювання (Throttling):</strong> Захист бекенд-сервісів від перевантаження.</li><li><strong>Кешування:</strong> Покращення продуктивності шляхом кешування відповідей API.</li><li><strong>Моніторинг та логування:</strong> Інтеграція з Amazon CloudWatch для відстеження метрик API та записування логів.</li><li><strong>Перетворення запитів та відповідей:</strong> Можливість модифікації заголовків, параметрів та тіла запитів і відповідей.</li><li><strong>Версіонування API:</strong> Підтримка кількох версій API одночасно.</li><li><strong>Інтеграція з іншими сервісами AWS:</strong> Легка інтеграція з Lambda, EC2, S3, DynamoDB та іншими сервісами AWS.</li><li><strong>Безпека:</strong> Захист від поширених веб-загроз.</li><li><strong>HTTP API (новіший варіант):</strong> Легший та дешевший варіант для проксування HTTP-запитів до бекендів.</li></ul><p><strong>Уявіть:</strong> AWS API Gateway як <strong>центральну диспетчерську вежу</strong> 🗼 для всіх ваших API, розташованих в хмарі AWS. Вона приймає всі вхідні запити, перевіряє дозволи, керує трафіком та направляє запити до потрібних бекенд-сервісів.</p><h4 id="🐳-kong-gateway" tabindex="-1">🐳 Kong Gateway <a class="header-anchor" href="#🐳-kong-gateway" aria-label="Permalink to “🐳 Kong Gateway”">​</a></h4><p><strong>Що це?</strong></p><p>Kong Gateway - це <strong>опенсорсний шлюз API</strong>, розроблений на основі Nginx та Lua. Він є платформо-незалежним і може бути розгорнутий у різних середовищах (хмара, локально, контейнери). Kong пропонує велику екосистему плагінів для розширення його функціональності.</p><p><strong>Основні можливості:</strong></p><ul><li><strong>Маршрутизація запитів:</strong> Гнучке налаштування маршрутів до ваших бекенд-сервісів.</li><li><strong>Аутентифікація:</strong> Підтримка різних методів аутентифікації через плагіни (Key Auth, JWT, OAuth 2.0, Basic Auth тощо).</li><li><strong>Контроль трафіку:</strong> Обмеження швидкості, регулювання, балансування навантаження.</li><li><strong>Плагіни:</strong> Велика кількість плагінів для додавання функціональності, такої як авторизація, кешування, трансформація запитів/відповідей, логування, моніторинг тощо.</li><li><strong>Масштабованість:</strong> Розроблений для горизонтального масштабування.</li><li><strong>Продуктивність:</strong> Побудований на Nginx, що забезпечує високу продуктивність.</li><li><strong>Гнучкість розгортання:</strong> Підтримка різних платформ та способів розгортання (Docker, Kubernetes, bare metal).</li></ul><p><strong>Уявіть:</strong> Kong Gateway як <strong>гнучкий та розширюваний комутатор</strong> 🎛️ для ваших API. Ви можете налаштувати його під свої потреби, додаючи різні &quot;модулі&quot; (плагіни) для керування трафіком, безпекою та іншими аспектами.</p><h4 id="🔑-apigee-google-cloud" tabindex="-1">🔑 Apigee (Google Cloud) <a class="header-anchor" href="#🔑-apigee-google-cloud" aria-label="Permalink to “🔑 Apigee (Google Cloud)”">​</a></h4><p><strong>Що це?</strong></p><p>Apigee API Management, частина Google Cloud, є <strong>комплексною платформою для керування API повного життєвого циклу</strong>. Вона надає інструменти для проєктування, захисту, публікації, аналізу та монетизації API.</p><p><strong>Основні можливості:</strong></p><ul><li><strong>Проєктування та моделювання API:</strong> Створення специфікацій API (наприклад, OpenAPI) та віртуальних API.</li><li><strong>Безпека:</strong> Захист API за допомогою різних політик безпеки, включаючи OAuth, API Keys, контроль доступу.</li><li><strong>Керування трафіком:</strong> Обмеження швидкості, регулювання, балансування навантаження.</li><li><strong>Кешування:</strong> Покращення продуктивності шляхом кешування відповідей.</li><li><strong>Моніторинг та аналітика:</strong> Детальна аналітика використання API, виявлення проблем.</li><li><strong>Монетизація API:</strong> Можливості для тарифікації використання API.</li><li><strong>Портал розробника:</strong> Створення порталу для розробників, щоб вони могли знаходити та використовувати ваші API.</li><li><strong>Політики (Policies):</strong> Широкий набір готових політик для керування різними аспектами API.</li></ul><p><strong>Уявіть:</strong> Apigee як <strong>центр керування польотами</strong> ✈️ для всіх ваших API. Він надає повний набір інструментів для планування, виконання, контролю та аналізу &quot;польотів&quot; ваших API, забезпечуючи їхню безпеку та ефективність.</p><p><strong>Вибір шлюзу API залежить від:</strong></p><ul><li><strong>Вашої інфраструктури:</strong> Чи використовуєте ви вже певну хмарну платформу?</li><li><strong>Ваших потреб у функціональності:</strong> Які функції керування API вам потрібні?</li><li><strong>Вашого бюджету:</strong> Керовані сервіси можуть бути дорожчими за самостійне розгортання.</li><li><strong>Вашої команди та її досвіду:</strong> З якими технологіями ваша команда вже знайома?</li></ul><p>Використання шлюзу API є рекомендованою практикою для більшості середніх та великих API, оскільки вони забезпечують централізоване керування, підвищують безпеку та спрощують масштабування.</p>',24)]))}const c=o(a,[["render",g]]);export{I as __pageData,c as default};
